<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Edit Audiometry Record</title><style>
:root{--line:#e5e7eb;--bg:rgba(15,23,42,.55);--panel:#fff;--text:#111827;--muted:#6b7280;--green:#389B5B}
*{box-sizing:border-box}body{margin:0;font-family:"Poppins","Segoe UI",Tahoma,Geneva,Verdana,sans-serif;background:#f3f4f6}.overlay{min-height:100vh;background:var(--bg);display:grid;place-items:center;padding:24px}.modal{width:min(980px,100%);background:var(--panel);border-radius:20px;box-shadow:0 20px 55px rgba(15,23,42,.25);padding:26px}h1{margin:0 0 6px;font-size:2.1rem}.muted{margin:0;color:var(--muted)}.panel{margin-top:18px;border:1px solid #e8ebf2;border-radius:16px;padding:16px}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.field{display:block;font-size:.9rem;color:#1f2937}.field input,.field select,.field textarea{margin-top:6px}input,select,textarea{width:100%;border:1px solid #d7dce7;border-radius:10px;padding:11px 12px;font:inherit}textarea{min-height:100px;resize:vertical}.full{grid-column:1/-1}.actions{margin-top:14px;display:flex;justify-content:space-between;gap:8px;flex-wrap:wrap}.btn{border:1px solid #d1d5db;border-radius:10px;padding:10px 14px;background:#fff;color:#374151;text-decoration:none;font-size:.92rem;display:inline-flex;align-items:center;gap:6px;cursor:pointer}.btn.primary{background:var(--green);border-color:var(--green);color:#fff;font-weight:600}.req{color:#dc2626}@media (max-width:760px){.grid{grid-template-columns:1fr}}
</style></head><body><div class="overlay"><form class="modal" method="post" action="#" id="modalForm" novalidate><h1>Edit Audiometry Record</h1><p class="muted">Update examination findings and recommendation.</p><div class="panel"><div class="grid"><label class="field">Employee <span class="req">*</span><input name="employee_name" type="text" value="Nur Hidayah" required></label><label class="field">Exam Date <span class="req">*</span><input name="exam_date" type="date" value="2026-03-13" required></label><label class="field">Result <span class="req">*</span><input name="result" type="text" value="Normal threshold" required></label><label class="field">Status <span class="req">*</span><select name="status" required><option>Completed</option><option>Review</option><option>Pending</option></select></label><label class="field full">Recommendation <span class="req">*</span><textarea name="recommendation" required>Continue annual audiometry surveillance and reinforce hearing protection compliance.</textarea></label></div></div><div class="actions"><a class="btn" href="audiometry_examination.php">Cancel</a><button class="btn primary" type="submit">Update Record</button></div></form></div><script>(function(){const form=document.getElementById('modalForm');form.addEventListener('submit',function(e){if(!form.checkValidity()){e.preventDefault();form.reportValidity();}});}());</script></body></html>

